def socketConnect(host, port):
    socketConn = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    socketConn.connect((host, port))
    return socketConn

def modbusConnect(host, port):
    modbusConn = ModbusClient(host=host, port=port, auto_open=True)
    return modbusConn

